export type BlogCategory = "text-tools" | "developer-tools" | "generators" | "finance" | "lifestyle" | "utility";

export interface ContentBlock {
  type: "paragraph" | "heading" | "code" | "list" | "callout" | "cta" | "faq" | "embed" | "summary" | "tip" | "warning" | "calc" | "comparison" | "tool-cta";
  text?: string;
  items?: string[];
  language?: string;
  code?: string;
  tool?: string;
  toolName?: string;
  toolDescription?: string;
  buttonText?: string;
  faqItems?: { question: string; answer: string }[];
  title?: string;
  steps?: string[];
  headers?: string[];
  rows?: string[][];
}

export interface BlogPost {
  slug: string;
  category: BlogCategory;
  date: string;
  readingTime: number;
  heroImages?: string[];
  thumbnailAlt: { en: string; ko: string };
  translations: {
    en: { title: string; summary: string; content: ContentBlock[] };
    ko: { title: string; summary: string; content: ContentBlock[] };
  };
  relatedTools: { slug: string; name: { en: string; ko: string } }[];
  relatedPosts: string[];
}

