export function getPostTags(slug: string): BlogTag[] {
  return blogTagMapping[slug] ?? ["tool-guide"];
}

const blogTagOgImage: Record<BlogTag, string> = {
  "tool-guide": "/images/blog/tool-guide-og.svg",
  "finance-tax": "/images/blog/finance-og.svg",
  "image-file": "/images/blog/image-file-og.svg",
  lifestyle: "/images/blog/lifestyle-og.svg",
};

export function getPostOgImage(slug: string): string {
  const tags = getPostTags(slug);
  return blogTagOgImage[tags[0]] ?? blogTagOgImage["tool-guide"];
}

function sortByDateDesc(posts: BlogPost[]): BlogPost[] {
  return [...posts].sort((a, b) => b.date.localeCompare(a.date));
}

export function getPostsByTag(tag: BlogTag | "all"): BlogPost[] {
  if (tag === "all") return sortByDateDesc(blogPosts);
  return sortByDateDesc(
    blogPosts.filter((p) => (blogTagMapping[p.slug] ?? ["tool-guide"]).includes(tag))
  );
}

export function getTagCounts(): Record<BlogTag | "all", number> {
  const counts: Record<string, number> = { all: blogPosts.length };
  for (const tag of blogTagOrder) counts[tag] = 0;
  for (const post of blogPosts) {
    const tags = blogTagMapping[post.slug] ?? ["tool-guide"];
    for (const tag of tags) counts[tag] = (counts[tag] ?? 0) + 1;
  }
  return counts as Record<BlogTag | "all", number>;
}

export const featuredSlugs = [
  "image-kb-guide",
  "dsr-guide",
  "excel-merge-guide",
  "accident-settlement-guide",
];

export function getFeaturedPosts(): BlogPost[] {
  return featuredSlugs
    .map((slug) => blogPosts.find((p) => p.slug === slug))
    .filter((p): p is BlogPost => p !== undefined);
}

