// Apply hero images from mapping
for (const post of blogPosts) {
  const imgs = blogHeroImages[post.slug];
  if (imgs) post.heroImages = imgs;
}

export function getPostBySlug(slug: string): BlogPost | undefined {
  return blogPosts.find((p) => p.slug === slug);
}

export function getPostsByCategory(category: BlogCategory | "all"): BlogPost[] {
  if (category === "all") return blogPosts;
  return blogPosts.filter((p) => p.category === category);
}

export function getPaginatedPosts(
  posts: BlogPost[],
  page: number
): { posts: BlogPost[]; totalPages: number } {
  const totalPages = Math.max(1, Math.ceil(posts.length / POSTS_PER_PAGE));
  const start = (page - 1) * POSTS_PER_PAGE;
  return { posts: posts.slice(start, start + POSTS_PER_PAGE), totalPages };
}

export function getAllSlugs(): string[] {
  return blogPosts.map((p) => p.slug);
}

export function getPostsByTool(toolSlug: string, limit = 3): BlogPost[] {
  return blogPosts
    .filter((p) => p.relatedTools.some((t) => t.slug === toolSlug))
    .slice(0, limit);
}
